+      const emails = pipeline.emailAdapter.getSentEmails();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]!.to).toBe('alice@example.com');
+
+      // SMS goes to phone number
+      const messages = pipeline.smsAdapter.getSentMessages();
+      expect(messages).toHaveLength(1);
+      expect(messages[0]!.to).toBe('+15551234567');
+
+      // Webhook goes to configured URL
+      expect(pipeline.webhookCalls).toHaveLength(1);
+      expect(pipeline.webhookCalls[0]!.url).toBe('https://hooks.example.com/notify');
+
+      // History has all channels logged
+      const logs = pipeline.historyService.getAll();
+      expect(logs).toHaveLength(4); // in-app + email + sms + webhook
+      const channels = logs.map((l) => l.channel).sort();
+      expect(channels).toEqual(['email', 'in-app', 'sms', 'webhook']);
+    });
+
+    it('should handle multiple users with different preferences', async () => {
+      // User 1: email only (default)
+      const user1 = makeUser({
+        id: 'user-1',
+        email: 'alice@example.com',
+      });
+
+      // User 2: SMS + webhook only
+      const user2 = makeUser({
+        id: 'user-2',
+        email: 'bob@example.com',
+        phone: '+15559999999',
+        notificationPreferences: {
+          email: { enabled: false },
+          sms: { enabled: true },
+          webhook: { enabled: true },
+        },
+      });
+
+      await pipeline.eventBus.emit(makeOrderCreatedEvent(user1, makeOrder({ id: 'order-1', userId: 'user-1' })));
+      await pipeline.eventBus.emit(makeOrderCreatedEvent(user2, makeOrder({ id: 'order-2', userId: 'user-2' })));
+      await pipeline.service.flush();
+
+      // User 1: email only
+      const emails = pipeline.emailAdapter.getSentEmails();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]!.to).toBe('alice@example.com');
+
+      // User 2: SMS + webhook
+      const messages = pipeline.smsAdapter.getSentMessages();
+      expect(messages).toHaveLength(1);
+      expect(messages[0]!.to).toBe('+15559999999');
+
+      expect(pipeline.webhookCalls).toHaveLength(1);
+
+      // Total in-memory notifications: 2
+      expect(pipeline.service.getNotificationCount()).toBe(2);
+
+      // History: user1 (in-app + email) + user2 (in-app + sms + webhook) = 5
+      expect(pipeline.historyService.getCount()).toBe(5);
+    });
+  });
+});

